import React from 'react';
import TabelaRelatorioEconomico from '../components/TabelaRelatorioEconomico';

const anoAtual = new Date().getFullYear();
const dataLinhas = [
  `31/03/${anoAtual}`,
  `31/03/${anoAtual}`,
  `31/03/${anoAtual}`,
  `30/06/${anoAtual}`,
  `30/06/${anoAtual}`,
  `30/06/${anoAtual}`,
];

export default function RelatorioPrimeiroSemestre() {
  return <TabelaRelatorioEconomico datasPadrao={dataLinhas} />;
}
